mapper.insert:
INSERT INTO t_ai_action_log (
    log_id, agent_id, agent_name, session_id, tool, category, target, summary
) VALUES (
    #{logId}, #{agentId}, #{agentName}, #{sessionId},
    #{tool}, #{category}, #{target}, #{summary}
)

mapper.select:
SELECT l.log_id, l.agent_id, l.agent_name, l.session_id, l.tool, l.category, l.target, l.summary, l.created_at
FROM   t_ai_action_log l
JOIN   t_ai_agent a ON a.agent_id = l.agent_id
                   AND a.owner_account_sn = #{ownerAccountSn}


        l.category = #{category}


ORDER BY l.created_at DESC
LIMIT  #{limit}
